# Default parameter
def greet(name, greeting='Hello'):
    return f'{greeting}, {name}!'

print(greet('Alice'))          # Hello, Alice!
print(greet('Bob', 'Hi'))      # Hi, Bob!

# *args
def total(*args):
    return sum(args)

print(total(1, 2, 3))     # 6
print(total(10, 20))      # 30

# **kwargs
def profile(**kwargs):
    for key, val in kwargs.items():
        print(f'{key}: {val}')

profile(name='Alice', age=30, city='NYC')
